INSERT INTO `exam_question` VALUES (1, 46, '高三', 1, '下列句子中语法正确的一项是？', '[{\"label\":\"A\",\"content\":\"She don\'t like it.\"},{\"label\":\"B\",\"content\":\"He doesn\'t likes it.\"},{\"label\":\"C\",\"content\":\"They doesn\'t want to go.\"},{\"label\":\"D\",\"content\":\"We don\'t have any money.\"}]', 'D', '第三人称单数主语用 doesn\'t，复数主语用 don\'t', 2, 5.0, '助动词用法', 0, 1, 0, '2026-03-05 10:00:00', NULL);
INSERT INTO `exam_question` VALUES (2, 46, '高三', 1, '下列句子中有语法错误的一项是？', '[{\"label\":\"A\",\"content\":\"I have been here for two hours.\"},{\"label\":\"B\",\"content\":\"He has gone to Beijing yesterday.\"},{\"label\":\"C\",\"content\":\"She will come tomorrow.\"},{\"label\":\"D\",\"content\":\"They are playing now.\"}]', 'B', '有具体过去时间状语 yesterday，应使用一般过去时 went，不能用完成时', 2, 5.0, '时态用法', 0, 1, 0, '2026-03-05 10:00:00', NULL);
INSERT INTO `exam_question` VALUES (3, 45, '高三', 1, '函数 f(x) = x² - 4x + 3 的对称轴方程是？', '[{\"label\":\"A\",\"content\":\"x=1\"},{\"label\":\"B\",\"content\":\"x=2\"},{\"label\":\"C\",\"content\":\"x=3\"},{\"label\":\"D\",\"content\":\"x=4\"}]', 'B', '二次函数对称轴 x = -b/(2a) = -(-4)/(2×1) = 2', 2, 5.0, '二次函数', 0, 1, 0, '2026-03-05 10:00:00', NULL);
INSERT INTO `exam_question` VALUES (4, 45, '高三', 2, '下列各式中，属于指数式的有哪些？', '[{\"label\":\"A\",\"content\":\"2³=8\"},{\"label\":\"B\",\"content\":\"log₂8=3\"},{\"label\":\"C\",\"content\":\"2⁴=16\"},{\"label\":\"D\",\"content\":\"log₂16=4\"}]', 'AC', 'a^n = N 是指数形式，A中 2³=8、C中 2⁴=16 均为指数式', 3, 10.0, '指数与对数', 0, 1, 0, '2026-03-05 10:00:00', NULL);
INSERT INTO `exam_question` VALUES (5, 47, '高三', 1, '物体做自由落体运动时，下列说法正确的是？', '[{\"label\":\"A\",\"content\":\"速度保持不变\"},{\"label\":\"B\",\"content\":\"加速度逐渐增大\"},{\"label\":\"C\",\"content\":\"合外力为零\"},{\"label\":\"D\",\"content\":\"加速度恒为重力加速度 g，约9.8m/s²\"}]', 'D', '自由落体运动只受重力，加速度恒为 g ≈ 9.8m/s²，方向竖直向下', 2, 5.0, '自由落体运动', 0, 1, 0, '2026-03-05 10:00:00', NULL);
INSERT INTO `exam_question` VALUES (6, 48, '高三', 1, '关于化学平衡移动，下列说法正确的是？', '[{\"label\":\"A\",\"content\":\"升温一定能促进反应正向进行\"},{\"label\":\"B\",\"content\":\"增大压强平衡一定正向移动\"},{\"label\":\"C\",\"content\":\"加入催化剂可改变平衡位置\"},{\"label\":\"D\",\"content\":\"减小生成物浓度，平衡将正向移动\"}]', 'D', '减小生成物浓度，相当于减少生成物量，平衡将向正反应方向移动', 3, 5.0, '化学平衡', 0, 1, 0, '2026-03-05 10:00:00', NULL);
INSERT INTO `exam_question` VALUES (7, 44, '高三', 3, '鲁迅被誉为\"民族魂\"，是中国现代文学的奠基人。（判断对错）', NULL, '对', '鲁迅是我国伟大的文学家、思想家和革命家，被誉为\"民族魂\"', 1, 5.0, '鲁迅与现代文学', 0, 1, 0, '2026-03-05 10:00:00', NULL);
INSERT INTO `exam_question` VALUES (8, 44, '高三', 4, '请简要分析《出师表》中诸葛亮\"鞠躬尽瘁，死而后已\"所体现的精神内涵。', NULL, '体现了诸葛亮对汉室的忠贞不渝、鞠躬尽瘁的奉献精神，以及明知难为而为之的坚定意志和责任担当。', '语文阅读理解', 1, NULL, '语文阅读理解', 0, 1, 0, '2026-03-05 10:00:00', NULL);
INSERT INTO `exam_question` VALUES (9, 50, '高三', 1, '下列关于劳动合同的说法，正确的是？', '[{\"label\":\"A\",\"content\":\"劳动合同到期后劳动关系自动终止，无需任何手续\"},{\"label\":\"B\",\"content\":\"劳动合同期满，双方可以协商续签合同\"},{\"label\":\"C\",\"content\":\"试用期内用人单位可以随意解除合同\"},{\"label\":\"D\",\"content\":\"劳动合同一旦签订，任何一方不得解除\"}]', 'B', '劳动合同期满，双方可协商续签；试用期内解除合同也需满足法定条件', 2, 5.0, '劳动合同制度', 0, 1, 0, '2026-03-05 10:00:00', NULL);
INSERT INTO `exam_question` VALUES (10, 51, '高三', 1, '下列对唐朝三省六部制理解正确的是？', '[{\"label\":\"A\",\"content\":\"三省六部制是汉朝建立的\"},{\"label\":\"B\",\"content\":\"三省六部制加强了地方分裂势力\"},{\"label\":\"C\",\"content\":\"三省分别是中书省、门下省、参知政事\"},{\"label\":\"D\",\"content\":\"三省六部制的目的是加强皇权、提高行政效率\"}]', 'D', '三省六部制是隋朝创立、唐朝完善的中央官制，目的是加强皇权、提高行政效率', 2, 5.0, '唐朝政治制度', 0, 1, 0, '2026-03-05 10:00:00', NULL);
