INSERT INTO `question` VALUES (1, 1, 1, '下列哪个小数最大？', 1, 1, 5, 'D', '比较小数大小先看整数部分，整数部分相同再依次比较小数各位', '小数大小比较', '2024年小学数学模拟题', 0, 1, '2026-03-05 10:00:00', NULL);
INSERT INTO `question` VALUES (2, 2, 1, '计算：125 × 8 = ?', 1, 1, 5, 'C', '125 × 8 = 1000，注意不要计算错误', '整数乘法', '人教版六年级数学', 0, 1, '2026-03-05 10:00:00', NULL);
INSERT INTO `question` VALUES (3, 3, 1, 'She _____ to school every day. (go)', 1, 1, 5, 'C', '主语是第三人称单数 She，一般现在时动词需加 -s/-es', '动词第三人称单数变形', '小学英语六年级', 0, 1, '2026-03-05 10:00:00', NULL);
INSERT INTO `question` VALUES (4, 4, 2, '下列关于RNA的说法，正确的是？', 1, 2, 5, 'B', 'RNA在细胞质和细胞核中都有分布，参与基因的表达过程', '细胞的结构与功能', '初一生物', 0, 1, '2026-03-05 10:00:00', NULL);
INSERT INTO `question` VALUES (5, 5, 2, '在数轴上，下列选项中属于负整数的是？', 1, 1, 5, 'C', '负整数是小于0的整数，-0.5是负数但不是整数', '整数的分类', '初一数学', 0, 1, '2026-03-05 10:00:00', NULL);
INSERT INTO `question` VALUES (6, 5, 2, '直线 AB 与直线 CD 平行，一条直线与两直线相交，则同位角的关系是？', 1, 2, 5, 'B', '两直线平行，同位角相等；内错角相等；同旁内角互补', '平行线与截线', '初一数学', 0, 1, '2026-03-05 10:00:00', NULL);
INSERT INTO `question` VALUES (7, 6, 2, '下列变化中，属于化学变化的是？', 1, 2, 5, 'D', '化学变化有新物质生成，铁生锈是铁与氧气和水反应生成氧化铁，属于化学变化', '物理变化与化学变化', '初一化学', 0, 1, '2026-03-05 10:00:00', NULL);
INSERT INTO `question` VALUES (8, 7, 2, '下列属于物理变化的是？', 1, 1, 5, 'A', '物理变化不改变物质的组成和化学性质，冰融化成水只是状态改变', '物理变化与化学变化', '初一物理', 0, 1, '2026-03-05 10:00:00', NULL);
INSERT INTO `question` VALUES (9, 28, 5, '第二次世界大战中，1945年日本正式宣布投降是在哪一天？', 1, 2, 5, 'B', '1945年8月15日日本宣布无条件投降，9月2日正式签署投降书', '第二次世界大战', '高一历史', 0, 1, '2026-03-05 10:00:00', NULL);
INSERT INTO `question` VALUES (10, 29, 5, '关于牛顿第二定律，下列说法正确的是？', 1, 2, 5, 'B', 'F = ma，合外力等于质量与加速度的乘积，方向与合外力方向相同', '牛顿第二定律', '高一物理', 0, 1, '2026-03-05 10:00:00', NULL);
