INSERT INTO `sys_email_template` VALUES (1, 'lesson_notify_teacher', '上课提醒-教师版', '【上课提醒】${lessonDate} ${startTime} ${courseName} 即将开始', '<div style=\"font-family:\'Microsoft YaHei\',sans-serif;max-width:600px;margin:0 auto;padding:20px;border:1px solid #e0e0e0;border-radius:8px;\">\n  <h2 style=\"color:#667eea;\">📚 上课提醒</h2>\n  <p>尊敬的 <strong>${teacherName}</strong> 老师，您好！</p>\n  <p>您有一节课程即将开始，请提前安排好时间。</p>\n  <table style=\"width:100%;border-collapse:collapse;margin:16px 0;\">\n    <tr><td style=\"padding:8px;background:#f5f5f5;font-weight:bold;\">课程名称</td><td style=\"padding:8px;\">${courseName}</td></tr>\n    <tr><td style=\"padding:8px;background:#f5f5f5;font-weight:bold;\">上课日期</td><td style=\"padding:8px;\">${lessonDate}</td></tr>\n    <tr><td style=\"padding:8px;background:#f5f5f5;font-weight:bold;\">上课时间</td><td style=\"padding:8px;\">${startTime} - ${endTime}</td></tr>\n    <tr><td style=\"padding:8px;background:#f5f5f5;font-weight:bold;\">上课地点</td><td style=\"padding:8px;\">${location}</td></tr>\n    <tr><td style=\"padding:8px;background:#f5f5f5;font-weight:bold;\">学生人数</td><td style=\"padding:8px;\">${studentCount} 人</td></tr>\n  </table>\n  <p style=\"color:#999;font-size:12px;\">此邮件由系统自动发送，请勿回复。</p>\n</div>', '[\"lessonDate\",\"startTime\",\"endTime\",\"courseName\",\"location\",\"teacherName\",\"studentCount\"]', 'teacher', 1, 1, '2026-03-13 21:41:12', NULL);
INSERT INTO `sys_email_template` VALUES (2, 'lesson_notify_parent', '上课提醒-家长版', '【上课提醒】您的孩子 ${studentName} 今日课程提醒', '<div style=\"font-family:\'Microsoft YaHei\',sans-serif;max-width:600px;margin:0 auto;padding:20px;border:1px solid #e0e0e0;border-radius:8px;\">\n  <h2 style=\"color:#667eea;\">📚 上课提醒</h2>\n  <p>尊敬的 <strong>${parentName}</strong> 家长，您好！</p>\n  <p>您的孩子 <strong>${studentName}</strong> 有一节课程即将开始，请提醒其做好准备。</p>\n  <table style=\"width:100%;border-collapse:collapse;margin:16px 0;\">\n    <tr><td style=\"padding:8px;background:#f5f5f5;font-weight:bold;\">课程名称</td><td style=\"padding:8px;\">${courseName}</td></tr>\n    <tr><td style=\"padding:8px;background:#f5f5f5;font-weight:bold;\">授课教师</td><td style=\"padding:8px;\">${teacherName}</td></tr>\n    <tr><td style=\"padding:8px;background:#f5f5f5;font-weight:bold;\">上课日期</td><td style=\"padding:8px;\">${lessonDate}</td></tr>\n    <tr><td style=\"padding:8px;background:#f5f5f5;font-weight:bold;\">上课时间</td><td style=\"padding:8px;\">${startTime} - ${endTime}</td></tr>\n    <tr><td style=\"padding:8px;background:#f5f5f5;font-weight:bold;\">上课地点</td><td style=\"padding:8px;\">${location}</td></tr>\n  </table>\n  <p style=\"color:#999;font-size:12px;\">此邮件由系统自动发送，请勿回复。</p>\n</div>', '[\"lessonDate\",\"startTime\",\"endTime\",\"courseName\",\"location\",\"teacherName\",\"studentName\",\"parentName\"]', 'parent', 1, 1, '2026-03-13 21:41:12', NULL);
INSERT INTO `sys_email_template` VALUES (3, 'lesson_notify_student', '上课提醒-学生版', '【上课提醒】${lessonDate} ${startTime} ${courseName} 即将开始', '<div style=\"font-family:\'Microsoft YaHei\',sans-serif;max-width:600px;margin:0 auto;padding:20px;border:1px solid #e0e0e0;border-radius:8px;\">\n  <h2 style=\"color:#667eea;\">📚 上课提醒</h2>\n  <p>同学 <strong>${studentName}</strong>，您好！</p>\n  <p>您有一节课程即将开始，请提前出发，勿迟到！</p>\n  <table style=\"width:100%;border-collapse:collapse;margin:16px 0;\">\n    <tr><td style=\"padding:8px;background:#f5f5f5;font-weight:bold;\">课程名称</td><td style=\"padding:8px;\">${courseName}</td></tr>\n    <tr><td style=\"padding:8px;background:#f5f5f5;font-weight:bold;\">授课教师</td><td style=\"padding:8px;\">${teacherName}</td></tr>\n    <tr><td style=\"padding:8px;background:#f5f5f5;font-weight:bold;\">上课日期</td><td style=\"padding:8px;\">${lessonDate}</td></tr>\n    <tr><td style=\"padding:8px;background:#f5f5f5;font-weight:bold;\">上课时间</td><td style=\"padding:8px;\">${startTime} - ${endTime}</td></tr>\n    <tr><td style=\"padding:8px;background:#f5f5f5;font-weight:bold;\">上课地点</td><td style=\"padding:8px;\">${location}</td></tr>\n  </table>\n  <p style=\"color:#999;font-size:12px;\">此邮件由系统自动发送，请勿回复。</p>\n</div>', '[\"lessonDate\",\"startTime\",\"endTime\",\"courseName\",\"location\",\"teacherName\",\"studentName\"]', 'student', 1, 1, '2026-03-13 21:41:12', NULL);
INSERT INTO `sys_evaluation` VALUES (1, 7, '学生1', NULL, 1, 'Java高级编程与并发', 1, 5, '课程内容非常实用，讲解深入浅出，很适合进阶学习！', 1, '感谢你的认可，继续加油！', '2026-03-06 10:00:00', 0, '2026-03-05 10:00:00', NULL);
INSERT INTO `sys_evaluation` VALUES (2, 8, '学生2', NULL, 1, 'Java高级编程与并发', 1, 4, '内容很好，部分章节节奏偏快，建议适当放慢讲解速度。', 0, NULL, NULL, 0, '2026-03-06 10:00:00', NULL);
INSERT INTO `sys_evaluation` VALUES (3, 9, '学生3', NULL, 2, 'Spring Boot实战开发', 1, 5, 'Spring Boot这门课帮助我完成了后端进阶，强烈推荐！', 1, '很高兴课程对你有所帮助！', '2026-03-07 10:00:00', 0, '2026-03-06 10:00:00', NULL);
INSERT INTO `sys_evaluation` VALUES (4, 10, '学生4', NULL, 4, 'Vue3+TypeScript前端开发', 1, 5, 'Vue3和TypeScript讲得非常详细，案例丰富，学完即可直接上手。', 1, '感谢你的认可！', '2026-03-07 10:00:00', 0, '2026-03-07 10:00:00', NULL);
INSERT INTO `sys_evaluation` VALUES (5, 11, '学生5', NULL, 7, '机器学习入门与实践', 1, 3, '数学基础要求较高，建议先补充线性代数和概率论的前置知识。', 0, NULL, NULL, 0, '2026-03-07 10:00:00', NULL);
INSERT INTO `sys_evaluation` VALUES (6, 12, '学生6', NULL, 1, '2024年高三英语模拟考试一', 2, 5, '试卷难度适中，题目分布合理，非常有助于查漏补缺！', 1, '加油备考，高考必胜！', '2026-03-07 10:00:00', 0, '2026-03-07 10:00:00', NULL);
INSERT INTO `sys_evaluation` VALUES (7, 13, '学生7', NULL, 9, 'Docker与Kubernetes运维实战', 1, 4, '实操性很强，学完可以直接动手搭建，非常有收获。', 0, NULL, NULL, 0, '2026-03-08 10:00:00', NULL);
INSERT INTO `sys_evaluation` VALUES (8, 14, '学生8', NULL, 3, 'MySQL数据库开发与优化', 1, 5, 'MySQL优化这门课学完后，数据库性能调优问题基本都能应对！', 1, '很高兴课程能帮到你！', '2026-03-08 10:00:00', 0, '2026-03-08 10:00:00', NULL);
