INSERT INTO `sys_word` VALUES (1, 'apple', '/ˈæpəl/', '苹果', 'I eat an apple every day. 我每天吃一个苹果。', 1, '六年级', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (2, 'book', '/bʊk/', '书，书籍', 'She is reading a book. 她正在看书。', 1, '六年级', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (3, 'cat', '/kæt/', '猫', 'The cat is sleeping on the sofa. 那只猫在沙发上睡觉。', 1, '六年级', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (4, 'dog', '/dɔɡ/', '狗', 'My dog likes to play outside. 我的狗喜欢在外面玩耍。', 1, '六年级', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (5, 'happy', '/ˈhæpi/', '快乐的，幸福的', 'She looks very happy today. 她今天看起来很开心。', 1, '六年级', '形容词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (6, 'run', '/rʌn/', '跑，跑步', 'He runs every morning to stay fit. 他每天早晨跑步保持健康。', 1, '六年级', '动词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (7, 'school', '/skuːl/', '学校', 'I go to school every day. 我每天上学。', 1, '六年级', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (8, 'teacher', '/ˈtiːtʃər/', '老师，教师', 'My teacher is very kind and patient. 我的老师非常和蔼耐心。', 1, '六年级', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (9, 'water', '/ˈwɔːtər/', '水', 'Drink more water every day. 每天多喝水。', 1, '六年级', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (10, 'friend', '/frend/', '朋友', 'She is my best friend. 她是我最好的朋友。', 1, '六年级', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (11, 'because', '/bɪˈkɒz/', '因为', 'I am late because of the traffic jam. 我因为堵车迟到了。', 2, '初一', '连词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (12, 'different', '/ˈdɪfrənt/', '不同的', 'We are different in many ways. 我们在许多方面各不相同。', 2, '初一', '形容词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (13, 'environment', '/ɪnˈvaɪrənmənt/', '环境', 'We should protect the environment. 我们应该保护环境。', 2, '初一', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (14, 'exercise', '/ˈeksərsaɪz/', '锻炼，运动', 'Regular exercise is good for your health. 规律运动对健康有益。', 2, '初一', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (15, 'important', '/ɪmˈpɔːrtənt/', '重要的', 'Education is very important for everyone. 教育对每个人都非常重要。', 2, '初一', '形容词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (16, 'population', '/ˌpɒpjʊˈleɪʃn/', '人口', 'China has a very large population. 中国有非常庞大的人口。', 2, '初二', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (17, 'technology', '/tekˈnɒlədʒi/', '技术，科技', 'Technology has changed our daily life. 科技改变了我们的日常生活。', 2, '初二', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (18, 'develop', '/dɪˈveləp/', '发展，开发', 'We need to develop new skills continuously. 我们需要不断发展新技能。', 2, '初二', '动词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (19, 'understand', '/ˌʌndərˈstænd/', '理解，明白', 'Do you understand this question? 你明白这道题吗？', 2, '初二', '动词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (20, 'society', '/səˈsaɪəti/', '社会', 'We are all part of society. 我们都是社会的一部分。', 2, '初二', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (21, 'communicate', '/kəˈmjuːnɪkeɪt/', '交流，沟通', 'It is important to communicate clearly. 清晰地沟通非常重要。', 2, '初三', '动词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (22, 'achieve', '/əˈtʃiːv/', '实现，完成', 'You can achieve your goals with hard work. 努力就能实现你的目标。', 2, '初三', '动词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (23, 'challenge', '/ˈtʃælɪndʒ/', '挑战', 'Life is full of challenges and opportunities. 生活充满挑战与机遇。', 2, '初三', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (24, 'responsibility', '/rɪˌspɒnsəˈbɪləti/', '责任，责任感', 'We have a responsibility to protect nature. 我们有责任保护自然。', 3, '初三', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (25, 'opportunity', '/ˌɒpəˈtjuːnəti/', '机会，机遇', 'Never miss an opportunity to learn something new. 永远不要错过学习新事物的机会。', 3, '初三', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (26, 'innovation', '/ˌɪnəˈveɪʃn/', '创新，革新', 'Innovation is the driving force of progress. 创新是进步的驱动力。', 3, '高一', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (27, 'analyze', '/ˈænəlaɪz/', '分析，剖析', 'We need to analyze the data carefully before drawing conclusions. 得出结论前我们需要仔细分析数据。', 3, '高一', '动词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (28, 'consequence', '/ˈkɒnsɪkwəns/', '结果，后果', 'Think carefully about the consequences of your actions. 仔细考虑你行为的后果。', 3, '高一', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (29, 'significant', '/sɪɡˈnɪfɪkənt/', '重要的，显著的', 'This discovery is of significant importance. 这个发现具有重大意义。', 3, '高一', '形容词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (30, 'contribute', '/kənˈtrɪbjuːt/', '贡献，做贡献', 'Everyone can contribute to making society better. 每个人都能为让社会变得更好做出贡献。', 3, '高一', '动词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (31, 'phenomenon', '/fɪˈnɒmɪnən/', '现象', 'Global warming is a serious natural phenomenon. 全球变暖是一个严峻的自然现象。', 3, '高二', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (32, 'perspective', '/pəˈspektɪv/', '观点，视角', 'Try to see things from different perspectives. 尝试从不同角度看待事物。', 3, '高二', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (33, 'sustainable', '/səˈsteɪnəbl/', '可持续的', 'We must pursue sustainable development. 我们必须追求可持续发展。', 3, '高二', '形容词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (34, 'dilemma', '/dɪˈlemə/', '困境，两难局面', 'She faced a difficult moral dilemma. 她面临一个艰难的道德困境。', 3, '高二', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (35, 'fundamental', '/ˌfʌndəˈmentəl/', '基本的，根本的', 'Trust is fundamental to any healthy relationship. 信任是一切健康关系的基础。', 3, '高二', '形容词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (36, 'ambition', '/æmˈbɪʃn/', '雄心，抱负', 'He has the ambition to become a great scientist. 他有成为伟大科学家的抱负。', 2, '高三', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (37, 'accomplish', '/əˈkɒmplɪʃ/', '完成，实现', 'She accomplished all her goals ahead of schedule. 她提前实现了所有目标。', 2, '高三', '动词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (38, 'elaborate', '/ɪˈlæbərət/', '详尽的，精心制作的', 'The architect presented an elaborate design plan. 建筑师提交了一份精心设计的方案。', 3, '高三', '形容词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (39, 'inevitable', '/ɪnˈevɪtəbl/', '不可避免的', 'Change is inevitable in a rapidly developing world. 在快速发展的世界里，变化是不可避免的。', 3, '高三', '形容词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (40, 'contemporary', '/kənˈtempərəri/', '当代的，同时代的', 'Contemporary art reflects the spirit of our times. 当代艺术反映了我们时代的精神。', 3, '高三', '形容词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (41, 'beautiful', '/ˈbjuːtɪfəl/', '美丽的，漂亮的', 'What a beautiful day! 多美好的一天！', 1, '六年级', '形容词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (42, 'family', '/ˈfæməli/', '家庭，家人', 'Family is the most important thing in life. 家庭是生命中最重要的。', 1, '六年级', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (43, 'learn', '/lɜːrn/', '学习，了解', 'I want to learn English well. 我想学好英语。', 1, '六年级', '动词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (44, 'problem', '/ˈprɒbləm/', '问题，难题', 'Can you help me solve this problem? 你能帮我解决这个问题吗？', 2, '初一', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (45, 'question', '/ˈkwestʃən/', '问题，疑问', 'Do you have any questions? 你有什么问题吗？', 2, '初一', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (46, 'culture', '/ˈkʌltʃər/', '文化', 'Chinese culture is very rich and diverse. 中国文化非常丰富多样。', 2, '初二', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (47, 'government', '/ˈɡʌvərnmənt/', '政府', 'The government makes important decisions for citizens. 政府为市民做出重要决策。', 2, '初二', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (48, 'economy', '/ɪˈkɒnəmi/', '经济', 'The national economy is growing steadily. 国民经济正在稳步增长。', 3, '高一', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (49, 'civilization', '/ˌsɪvəlaɪˈzeɪʃn/', '文明', 'Ancient civilizations left us a rich cultural heritage. 古代文明给我们留下了丰富的文化遗产。', 3, '高二', '名词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
INSERT INTO `sys_word` VALUES (50, 'extraordinary', '/ɪkˈstrɔːrdnəri/', '非凡的，卓越的', 'She has an extraordinary talent for music. 她拥有非凡的音乐天赋。', 3, '高三', '形容词', 0, 1, 0, '2026-03-05 16:00:00', NULL);
