  INDEX `idx_menu_id`(`menu_id`) USING BTREE,
  INDEX `idx_button_id`(`button_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 26 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '菜单按钮关系表' ROW_FORMAT = Compact;

